INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-01986', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '為防制兒童或少年遭受利用從事性交之對價行為，危害兒童身心之健全發展，下列那一個選項正確？', '["針對上述狀況，現行防制、規範及保護兒童少年的法規名稱是「兒童及少年性交易防制條例」", "根據現行法律規範，檢察官、司法警察官及司法警察查獲及救援被利用從事性交對價關係之兒童或少 年被害人後，應於48小時內將被害人交由當地直轄市、縣（市）主管機關處理", "直轄市、縣（市）主管機關經評估被害人須緊急安置，應於安置起72小時內，評估有無繼續安置之必 要；經評估有安置必要者，應提出報告，聲請法院裁定", "主管機關應於被害人安置後60日內，向法院提出審前報告，包括安置評估及處遇方式之建議，以作為 法院認定是否繼續安置之參考"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01987', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '當今臺灣社會生育率低，其原因多元。若政府想要鼓勵民眾生育，提升生育率，在下列四個選項中，那 一個選項是社會政策相較容易介入，並產生影響民眾願意生育的效果？', '["市場托育費用太高、品質參差不齊，影響民眾生育意願", "現代社會青年人的生活型態與婚姻觀轉變，延遲結婚的進程", "婦女教育程度提升，考量教育投資及個人發展而全力投入勞動市場", "民眾理性計算結婚與養育子女的成本影響到個人自主與生活品質，選擇不婚或不生"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01988', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國於2015年公布長期照顧服務法，並於2017年6月正式施行。在下列選項中，那一個選項與長期照 顧服務法之法令規定不合？', '["長期照顧服務之提供，不得因服務對象之國籍而有差別待遇", "根據該法第21條，長照機構依服務內容，區分為居家式服務類、社區式服務類、機構住宿式服務類、 綜合式服務類及政府公告類別等", "長期照顧主管機關在訂定長照服務品質基準時，應以區域資源配置為中心原則", "多元文化是長照服務資源調查、配置與服務規劃發展時必須考慮的要素"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01989', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '以「歷史制度論」探究社會政策的制訂與發展，下列那個不符合此論點的敘述？', '["「歷史脈絡」是社會政策與制度生成的特殊環境", "新政策與制度的建立往往必須激進的打破歷史陳疴，才能新瓶裝新酒", "政治、經濟、宗教、意識型態、社會環境等往往與社會政策的形成產生特殊互動，成為社會政策的分 析基礎", "社會政策的形成與發展，往往與先前政策之間形成「路徑依賴」關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01990', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列那一個選項的論述最不符合「社會投資」（social investment）的理念與作為？', '["「社會投資」的福利政策認為放任的自由經濟造成貧富差距日益擴大，強力主張政府扮演所得再分配 的角色", "社會投資策略強調機會的平等，主張政府應將社會支出用在人力資本的發展上", "政府提供彈性與安全的短期公共工作機會，協助職業災害青年探索工作機會與適應，協助重返職場， 是屬於社會投資的策略", "政府近年來針對女性單親或弱勢婦女所推動的微型創業方案，可說是屬於社會投資策略的運用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01991', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國社會救助法對於低收入的認定，必須由戶籍所在地直轄市、縣（市）主管機關審核，符合家庭總收 入平均分配全家人口，每人每月在最低生活費以下，且家庭財產未超過中央、直轄市主管機關公告之當 年度一定金額者。該法有關最低生活費的設定，較符合以下那一個選項的論點？', '["絕對貧窮", "相對貧窮", "社會排除", "社會隔離"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01992', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '英國學者Richard M. Titmuss指出社會服務（現金與實物給付）是具有多元目標的多元體系。他認為多數', '["志願服務 體系", "家庭福利體系", "職業福利體系", "財稅福利體系  ⑤社會福利體系"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01993', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '「失業認定」是我國就業保險法之被保險人得以領取失業給付的行政判斷。在失業認定時，下列那一項 不符合請領失業給付的資格？', '["被保險人在辦理退保當日前3年內，保險年資合計必須滿6個月以上", "被保險人必須提出雇主開具的「非自願性失業證明」", "被保險人不接受工資低於其每月得請領失業給付數額之推介工作", "被保險人向公立就業服務機構辦理求職登記，經14天等待期仍無法推介就業"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01994', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '某高職學校的行政主管運用權勢，要求辦公室一位女性約聘員工跟他交往，並以考績表現及未來繼續聘 任要脅。這位女性員工感覺到被性騷擾及威脅，想要提出申訴。請問以上述的情況所造成的騷擾，適用 的法律是以下那一個？', '["性別教育平等法", "性別工作平等法", "性騷擾防治法", "性騷擾暴力防治法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01995', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '以「生命歷程觀點」（life course perspective）來探討與檢視身心障礙者的健康照顧政策，下面那一個選 項最為貼近該觀點的論述？', '["障礙者在不同年齡階段都有類似的基本健康與醫療服務需求；隨著年齡越大，醫療服務需求也越多", "身心障礙者的身心功能之復原狀況，受到其在醫療歷程的治療與復健經驗深深影響", "先天障礙者與後天障礙者，其障礙經驗與健康醫療需求不相同", "不同世代的障礙者在不同的歷史事件與社會經濟環境影響下，其所經歷的健康醫療與障礙經驗也不相同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01996', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '人民的居住正義是民國 100 年社會福利政策綱領的重要主張。以下有關社會住宅的相關選項，那一個選 項是不正確的？', '["新修正的「住宅法」是在106年公布實施的", "住宅法中所定義的社會住宅是指由政府興辦或獎勵民間興辦，供出租或在政府規範下買賣作非營利用 途的住宅", "依照新住宅法的規範，社會住宅應以直轄市、縣（市）轄區為計算範圍，提供至少百分之三十以上比 率出租給經濟或社會弱勢者", "對於未設籍在當地，但在該地區就學、就業有居住需求的民眾，政府或民間興建的社會住宅應提供一 定比率協助之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01997', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國相關法令中，對於弱勢民眾遭遇不合理對待、剝削、遺棄等緊急狀況而有危及生命安全與健康之情 形，均責成醫事人員、社會工作人員、警察人員、村里幹事或其他相關業務之執行人員負有向當地直轄 市、縣（市）主管機關通報之義務。在下列四個選項中，那一個選項與法令規定不合？', '["根據身心障礙者權益保障法之規定，當上述人員知悉身心障礙者有遭受遺棄之情形，應立即向直轄市、 縣（市）主管機關通報，至遲不得超過24小時", "根據兒童及少年福利與權益保障法之規定，當上述人員於執行職務時知悉兒童或少年有遭受遺棄之情 形，應立即向直轄市、縣（市）主管機關通報，至遲不得超過24小時", "根據老人福利法之規定，當上述人員於執行職務時知悉老人有遭受遺棄之情形，應立即向直轄市、縣 （市）主管機關通報，至遲不得超過24小時", "根據家庭暴力防治法之規定，當上述人員在執行職務時知悉有疑似家庭暴力，應立即通報當地主管機 關，至遲不得逾24小時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01998', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '我國社會保險的保險費率，下列那一項是採用「實績費率」？', '["勞工的醫療健康保險", "勞工的失業保險", "勞工的職業災害保險", "勞工的退休保險"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01999', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '老人福利法第2章經濟安全條文，下列所示何者錯誤？', '["中低收入戶老人未接受收容安置者，得申請發給生活津貼。不符合請領資格而領取津貼者，其領得之 津貼經主管機關告知，應於事實發生之日起50日內繳還，未繳還者依法移送行政執行", "依本法請領各項現金給付或補助之權利，不得扣押、讓與或提供擔保", "為保護老人之財產安全，各級主管機關應鼓勵其將財產交付信託", "金融主管機關應鼓勵信託業者及金融業者辦理財產信託，提供商業型不動產逆向抵押貸款服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02000', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '面對人口老化問題，政府在民國98年提出第一期友善關懷老人服務方案，並於102年再推出第二期計畫， 請針對第二期計畫的目標，下列所示何者錯誤？', '["提倡預防保健，促進健康老化", "建置友善環境，促進在地老化", "鼓勵終身學習，促進智慧老化", "推動社會參與，促進活力老化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02001', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '對於民國103年公布的身心障礙者權利公約施行法，下列條文內容何者錯誤？', '["本公約所揭示保障身心障礙者人權之規定，具有國內法律之效力", "政府應依公約規定建立身心障礙者權利報告制度，於本法施行後2年提出初次國家報告，之後每4年 提出國家報告", "各級政府機關執行公約保障各項身心障礙者人權規定所需之經費，應優先編列，逐步實施", "各級政府機關應依公約規定之內容，就其所主管之法規及行政措施於本法施行後 2 年優先檢視清單， 有不符公約規定者，應於本法施行後3年完成法規之增修、廢止及行政措施之改進，並於本法施行後 4年內，完成其餘法規之制（訂）定、修正或廢止及行政措施之改進"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02002', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '民國 104 年公布的「兒童及少年高風險家庭關懷輔導處遇實施計畫」，在權責分工中規定承辦單位接受 社會局（處）轉介個案不得無故拒絕，並應在接案後多少日之內進行訪視評估，且多久之內提出評估報 告？', '["5日內進行訪視評估並於1個月內提出評估報告", "10日內進行訪視評估並於1個月內提出評估報告", "15日內進行訪視評估並於1個月內提出評估報告", "20日內進行訪視評估並於1個月內提出評估報告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02003', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會救助法中的生活扶助條文內容，低收入戶成員中有下列情形包括年滿65歲、懷胎滿3個月或領有身 心障礙證明者，主管機關得依其原領取現金給付之金額，增加補助，但最高不得逾百分之多少？', '["20", "30", "40", "50"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02004', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '按國民年金法第 5 條內容，被保險人及受益人對保險人所為之核定案件發生爭議事項時，應於收到核定 通知文件之翌日起，多少日內先申請審議，對於審議結果不服時，得依法提起訴願及行政訴訟？', '["30日", "40日", "50日", "60日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02005', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '按家庭暴力防治法第13條所示，下列條文內容何者錯誤？', '["聲請保護令之程式或要件有欠缺者，法院應以裁定駁回之", "被害人得於審理時，聲請其親屬或個案輔導之社工人員、心理師陪同被害人在場，並得陳述意見", "法院於審理終結前，得聽取直轄市、縣（市）主管機關或社會福利機構之意見", "保護令事件得進行調解或和解"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02006', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依性侵害犯罪防治法第14條規定，法院、檢察署、軍事法院、軍事法院檢察署、司法、軍法警察機關及 醫療機構，應由經專業訓練之專人處理性侵害事件，前項專責人員每年應至少接受多少小時性侵害防治 專業訓練課程？', '["4小時", "6小時", "10小時", "12小時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02007', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關性別工作平等法在促進工作平等措施方面，其第15條條文內容，下列何者錯誤？', '["雇主於女性受僱者分娩前後，應使其停止工作，給予產假8星期", "妊娠3個月以上流產者，應使其停止工作，給予產假3星期", "受僱者妊娠期間，雇主應給予產檢假5日", "受僱者於其配偶分娩時，雇主應給予陪產假5日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02008', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '按兒童及少年性剝削防制條例第18條，直轄市、縣（市）主管機關至遲應於被害人安置後多少日內向法 院提出審前報告，並聲請法院裁定？', '["15日", "30日", "45日", "60日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02009', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列有關兩公約，即公民與政治權利國際公約及經濟社會文化權利國際公約的內容敘述，何者錯誤？', '["兩公約是聯合國在1966年頒定", "兩公約與世界人權宣言，合稱國際人權憲章", "我國在2009年通過兩公約施行法，且兩公約所揭示保障人權之規定具有國內法律之效力", "各級政府機關應依兩公約規定之內容，檢討所主管之法令及行政措施，有不符兩公約規定者，應於本 法施行後3年內完成法令之制（訂）定、修正或廢止及行政措施之改進"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02010', 'social-worker', 'social-worker-moex-107-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '對於社會福利公益信託許可及監督辦法，公益信託有下列各款情事，包括違反設立許可條件或監督命令、 為有害公益之行為、無正當理由連續 3 年不為活動。主管應通知委託人、信託監察人及受託人於多少日 內表示意見，屆期不表示或雖表示而無正當理由者，主管機關得依法廢止其許可及其他必要處置？', '["10日", "15日", "20日", "30日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:11+00:00", "source_pdf_sha1": "5659ee27e44f", "answer_pdf_sha1": "7fe5f1f09f6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
